#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        int V; scanf("%d", &V);
        int first = 1;
        for (int i = 0; i < N; ++i) {
            if (arr[i] != V) {
                if (!first) printf(" ");
                printf("%d", arr[i]);
                first = 0;
            }
        }
        if (first) printf("Empty array");
        printf("\n");
        free(arr);
    }
    return 0;
}

